() => {
  type Person = { name: string; role: string };
  const [items, setItems] = React.useState<Person[]>([{name:'Ada',role:'Programmer'},{name:'Alan',role:'Mathematician'}]);
  const [sel, setSel] = React.useState<Person | null>(null);
  return (<Stack>
    <List data={items} getTitle={(i)=>i.name} getSubtitle={(i)=>i.role} getItemKey={(i)=>i.name} selectionMode='single' reorderable selected={sel} onSelectionChange={(i)=>setSel(i)} onReorder={setItems} />
    <Typography variant='subtitle'>Selected: {sel?.name || '—'}</Typography>
  </Stack>);
}
